sql:
SELECT AVG(((new_value - previous_value) / previous_value) * 100) AS average_percentage_increase
FROM executive_changes
WHERE change_type = 'Raise';

external_knowledge:
- "Top-paid executives" refers to those with the highest cash pay in their respective industries;
- "Towers above the average earnings" means their cash pay is greater than the average worker pay in the industry;
- "Corporate realm" refers to the business and financial industries.

sql:
SELECT name, total_pay
FROM executives
WHERE total_pay > (SELECT AVG(total_pay) FROM executives);

SELECT name, total_pay
FROM executives
ORDER BY total_pay DESC;

SELECT industry_name 
FROM industry_averages 
WHERE average_ceo_pay > (SELECT AVG(total_pay) FROM executives);

SELECT total_pay_trend
FROM executive_pay_trends
WHERE year = 2022 AND total_pay_trend > 50;

